{
  "oneSentence": "AI Skills需按需选择，解决重复工作并补足知识短板，而非盲目追随热门。",
  "corePoints": [
    { "point": "Skills选择标准：解决重复工作和补足知识短板", "timestamp": 76 },
    { "point": "技术栈相关Skills最必要，应放在工程目录", "timestamp": 82 },
    { "point": "最有用的Skills是能进行真实验证的，如测试部署", "timestamp": 665 },
    { "point": "编写个人化Skills比追随热门更有价值", "timestamp": 2131 },
    { "point": "Skills适合自动化日常工作和知识管理", "timestamp": 2757 }
  ],
  "audience": ["程序员", "AI工具用户", "产品经理", "效率提升爱好者"],
  "valueScore": {
    "density": 8,
    "novelty": 7,
    "actionability": 9
  },
  "estimatedCostMinutes": 7,
  "steps": [
    { "title": "步骤1：理解Skills选择标准", "content": "判断一个Skill是否值得使用主要看两点：一是解决重复性工作，二是补足自身不擅长的知识领域。不要盲目追随热门Skills，而应从实际需求出发。技术栈相关的Skills通常是最必要的，但应放在工程目录而非全局。", "sourceTimestamp": 76 },
    { "title": "步骤2：应用技术栈相关Skills", "content": "在初始化工程时，使用\"find skills\"让Agent寻找必要的技术栈相关Skills，如React最佳实践等。这些Skills能帮助Agent遵循最佳实践，避免写出有安全或边界问题的代码。将这类Skills放在工程目录下，而非全局目录。", "sourceTimestamp": 82 },
    { "title": "步骤3：选择能进行真实验证的Skills", "content": "最有用的Skills是那些能让Agent对迭代结果进行真实验证的，如Playwright测试和Cortex内置的computer use。这类Skills能帮助开发任务真正闭环，完成整个循环。验证步骤对于人来说通常是繁琐且效率低下的，因此让AI自动完成特别有价值。", "sourceTimestamp": 665 },
    { "title": "步骤4：在开发工作流中应用Skills", "content": "建立包含需求讨论、计划执行、代码审查和发布验证的完整工作流程。使用\"grill me\"这类Skill帮助澄清需求细节，避免信息损失。让AI自行审查代码，从安全和性能视角检查问题。最后，让AI自行验证和发布，减少人工干预。", "sourceTimestamp": 906 },
    { "title": "步骤5：编写个人化Skills", "content": "不要只依赖现成Skills，可根据自己的工作流程编写个性化Skills。例如，将日常重复性工作(如邮件处理、代码同步、监控等)自动化。编写Skills时也不需要手动编码，可以描述工作流程让AI帮助完成。个人Skills往往比通用热门Skills更实用。", "sourceTimestamp": 2131 },
    { "title": "步骤6：用Skills管理数字资产", "content": "利用Skills自动化管理个人数字资产，如播客内容、读书笔记等。可编写Skills定期同步和编译内容为结构化知识，方便后续检索。Skills特别适合处理看似不起眼但每天重复的日常事务，这些恰恰是最值得自动化的。", "sourceTimestamp": 2659 }
  ],
  "cards": [
    { "type": "opinion", "title": "Skills不是越多越好", "explanation": "安装过多Skills可能导致Agent行为混乱，增加token消耗，甚至产生失控感。应采取保守策略，只在实际使用过程中发现Agent能力确实缺失时才安装相关Skills。不要被热门网红Skills吸引，而应关注实际需求。", "sourceTimestamp": 2146 },
    { "type": "method", "title": "设计与开发分离策略", "explanation": "前端设计可采用\"先设计后实现\"的策略：先用ChatGPT生成想要的页面风格图片，从中提取所需素材，再让Claude或Codex实现代码。这种方法特别适合landing page等对架构要求不高的页面，能有效避免纯AI生成的典型设计感。", "sourceTimestamp": 1503 },
    { "type": "reflection", "title": "对AI的信任与失控感", "explanation": "随着AI能力提升，人们逐渐从必须掌控AI产出的所有内容，转变为可以让AI自主掌控更多内容。这种变化伴随着心理接受度的提高，但也意味着我们需要为AI的行为背负责任。真正出问题时，负责的是人类而非AI。", "sourceTimestamp": 2421 }
  ],
  "actions": {
    "today": "检查你的工作流，找出一个重复性任务，探索是否有相关Skills可以自动化它。",
    "thisWeek": "尝试编写一个个人化Skills来解决你日常工作中最繁琐的一个环节，不必追求完美。",
    "longTerm": "建立自己的Skills库，逐步将重复性工作和知识管理任务自动化，形成第二大脑。"
  }
}

{
  "oneSentence": "选对 Skills 弥补短板，用 Loops 替代 Prompts，构建高效的 AI 编程与自动化工作流。",
  "corePoints": [
    { "point": "只在解决重复性工作或弥补知识盲区时引入 Skills", "timestamp": 249 },
    { "point": "真正的价值在于闭环验证，用 Loops 驱动替代单纯写 Prompt", "timestamp": 692 },
    { "point": "编码工作流转变为：忽略代码细节，关注架构地图与最终结果", "timestamp": 1261 }
  ],
  "audience": ["开发者", "独立黑客", "AI 工具极客"],
  "valueScore": {
    "density": 8,
    "novelty": 8,
    "actionability": 9
  },
  "estimatedCostMinutes": 8,
  "steps": [
    { "title": "按需筛选 Skills", "content": "不要试图安装所有热门 Skills。利用 find skills 工具，只安装当前工程必要的技术栈规范（如 React Best Practices），并将其安装在工程目录而非全局，保持 Agent 环境的精简和针对性。", "sourceTimestamp": 82 },
    { "title": "判断两类高价值场景", "content": "值得使用的 Skills 通常分为两类：一是解决高频重复性工作（如每天构建测试、运维检查）；二是不熟悉的领域（如营销、SEO），利用现成的专业知识库弥补自身短板。", "sourceTimestamp": 249 },
    { "title": "使用 Grill Me 澄清需求", "content": "在开始编码前，使用 Skills for Real Engineers 中的 Grill Me。它会让 AI 反过来审问你的需求细节，挖掘隐含条件，生成清晰的 Context.md 文档，防止因需求描述不清导致开发偏差。", "sourceTimestamp": 762 },
    { "title": "构建闭环验证 Loops", "content": "不要只写 Prompt，要写 Loops。利用 Playwright 或 Computer Use 等 Skills 让 AI 能够进行真实验证和自测，只有当 AI 能自我验证结果时，开发任务才算真正完成闭环。", "sourceTimestamp": 692 },
    { "title": "转变开发视角：重结果轻代码", "content": "改变逐行审查代码的习惯。关注点应从代码洁癖转移到架构地图（Architecture Map）的正确性，以及最终功能是否跑通。让 AI 自我 Review 或交叉 Review，你只需把控核心逻辑。", "sourceTimestamp": 1261 },
    { "title": "通过图转码实现前端设计", "content": "为避免前端出现“AI 味”，可先用 DALL-E 生成 Landing Page 设计图，再让 AI 提取素材并分层，最后由 Codex 还原成代码。这样既保证了设计感，又实现了落地。", "sourceTimestamp": 1503 }
  ],
  "cards": [
    { "type": "method", "title": "Grill Me 需求审问", "explanation": "在给 AI 布置开发任务前，使用 Grill Me Skill 让 AI 反向提问，挖掘需求背后的隐含细节和边界条件，生成清晰的开发文档，防止需求理解偏差。", "sourceTimestamp": 762 },
    { "type": "opinion", "title": "Loops > Prompts", "explanation": "单纯写 Prompt 容易中断，未来趋势是编写 Loops（工作流）。通过构建包含验证步骤的完整闭环，让 AI 自我驱动完成任务，而非人工反复介入。", "sourceTimestamp": 692 },
    { "type": "reflection", "title": "DRY 原则与失控感", "explanation": "遵循程序员 DRY 原则，任何重复三次的工作都应封装成 Skill。虽然会担心 AI 失控，但信任 AI 承担责任并构建自动化循环是效率提升的必经之路。", "sourceTimestamp": 2973 }
  ],
  "actions": {
    "today": "清理不常用的网红 Skills，尝试使用 grill me 梳理一个开发需求。",
    "thisWeek": "挑选一个日常重复琐事（如查邮件、看日志），利用 AI 编写一个专属 Skill。",
    "longTerm": "建立包含自动化测试、验证、部署的完整 AI 开发 Loops，逐步脱离代码细节审查。"
  }
}

{
  "oneSentence": "Skills应解决重复工作或弥补能力缺失，真正自动化依赖闭环验证。",
  "corePoints": [
    { "point": "判断Skill价值标准：解决重复工作或弥补短板", "timestamp": 249 },
    { "point": "Coding中最有用Skill是能实现真实验证闭环的", "timestamp": 665 },
